SECRET = "test-secret"
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="token")

# --- Permission definitions ---
class Permission(str, Enum):
    READ_POSTS = "read_posts"
    CREATE_POSTS = "create_posts"
    DELETE_POSTS = "delete_posts"
    MANAGE_USERS = "manage_users"
    VIEW_REPORTS = "view_reports"

# Role-to-permission mapping
ROLE_PERMISSIONS: dict[str, set[str]] = {
    "admin": {
        Permission.READ_POSTS, Permission.CREATE_POSTS,
        Permission.DELETE_POSTS, Permission.MANAGE_USERS,
        Permission.VIEW_REPORTS,
    },
    "editor": {
        Permission.READ_POSTS, Permission.CREATE_POSTS,
        Permission.DELETE_POSTS,
    },
    "viewer": {
        Permission.READ_POSTS,
    },
}

class User(BaseModel):
    username: str
    role: str
    permissions: set[str] = set()

def get_current_user(token: Annotated[str, Depends(oauth2_scheme)]) -> User:
    payload = jwt.decode(token, SECRET, algorithms=["HS256"])
    role = payload.get("role", "viewer")
    # Get permissions from role + any extra permissions
    perms = ROLE_PERMISSIONS.get(role, set())
    extra = set(payload.get("extra_permissions", []))
    return User(
        username=payload["sub"],
        role=role,
        permissions=perms | extra,
    )

CurrentUser = Annotated[User, Depends(get_current_user)]

def require_permissions(*required: str):
    """Dependency factory that checks for specific permissions."""
    def checker(current_user: CurrentUser) -> User:
        missing = set(required) - current_user.permissions
        if missing:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Missing permissions: {', '.join(sorted(missing))}",
            )
        return current_user
    return checker

@app.get("/posts")
def list_posts(
    user: Annotated[User, Depends(require_permissions(Permission.READ_POSTS))],
):
    return {"user": user.username, "action": "listing posts"}

@app.post("/posts")
def create_post(
    user: Annotated[User, Depends(require_permissions(Permission.CREATE_POSTS))],
):
    return {"user": user.username, "action": "creating post"}

